&lt;p&gt;寻找后继&lt;img data-src=&#34;E:%5Ctypora%E5%9B%BE%E7%89%87%5Cimage-20220322143106816.png&#34; alt=&#34;image-20220322143106816&#34;&gt;&lt;img data-src=&#34;E:%5Ctypora%E5%9B%BE%E7%89%87%5Cimage-20220322143418284.png&#34; alt=&#34;image-20220322143418284&#34;&gt;&lt;/p&gt;
